values.value:
[
  {
    "name": "notificationTypeName",
    "type": "string",
    "required": false,
    "help": "The DeveloperName of the CustomNotificationType to use by default.",
    "label": "Default Notification Type"
  },
  {
    "name": "defaultTargetId",
    "type": "salesforce-id",
    "required": false,
    "help": "Optional default record ID to link notifications to if not specified at runtime.",
    "label": "Default Target ID"
  }
]

{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "properties": {
    "notificationTypeName": {
      "type": "string",
      "description": "The DeveloperName of the CustomNotificationType to use by default."
    },
    "defaultTargetId": {
      "type": "string",
      "description": "Optional default record ID to link notifications to if not specified at runtime.",
      "format": "salesforce-id"
    }
  }
}

{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "properties": {
    "recipientIds": {
      "type": "array",
      "description": "List of User IDs to send notifications to"
    },
    "title": {
      "type": "string",
      "description": "Notification title",
      "maxLength": 255
    },
    "body": {
      "type": "string",
      "description": "Notification body/message text",
      "maxLength": 5000
    },
    "targetId": {
      "type": "string",
      "description": "Optional: Record ID to link the notification to",
      "format": "salesforce-id"
    }
  },
  "required": [
    "recipientIds",
    "title",
    "body"
  ]
}
